// Client Stub Procedure
PROCEDURE add_numbers_stub(a, b, server_address):
 // Step 1: Marshal parameters into network format
 request_packet = MARSHAL('add_numbers', a, b)

 // Step 2: Send request to server via RPC Runtime
 response_packet = RPC_SEND(server_address, request_packet)

 // Step 3: Unmarshal the response
 result = UNMARSHAL(response_packet)

 // Step 4: Return result to client application
 RETURN result

// Client Application Call
result = add_numbers_stub(10, 20, "192.168.1.100:8080")
PRINT result // Output: 30

// Server Stub Procedure
PROCEDURE add_numbers_server_stub(request_packet):
 // Step 1: Unmarshal request packet
 (procedure_name, a, b) = UNMARSHAL(request_packet)

 // Step 2: Route to actual server implementation
 IF procedure_name == 'add_numbers' THEN
 result = add_numbers_server(a, b)
 ELSE
 RAISE error("Unknown procedure")
 END IF

 // Step 3: Marshal result into response packet
 response_packet = MARSHAL(result)

 // Step 4: Send response back to client
 RETURN response_packet

// Server Implementation
PROCEDURE add_numbers_server(a, b):
 RETURN a + b

// Server Registration
RPC_REGISTER('add_numbers', add_numbers_server_stub)
RPC_LISTEN(8080)
